from typing import Dict, Optional

_db: Dict[str, Dict] = {}
_cache: Dict[str, Dict] = {}


def _snapshot(product: Dict) -> Dict:
    """Return a shallow copy of a product dict for safe external use."""
    return dict(product)


def add_product(product_id: str, name: str, price: float) -> None:
    """Add a product to the database and refresh the cache for that product.

    If a product with the same ID already exists, it will be replaced.
    """
    _db[product_id] = {"name": name, "price": price}
    # Keep cache consistent with DB
    _cache[product_id] = _snapshot(_db[product_id])


def get_product(product_id: str) -> Optional[Dict]:
    """Get product by ID. Uses the cache for repeated lookups.

    Returns a shallow copy of the product dict or None if not found.
    """
    cached = _cache.get(product_id)
    if cached is not None:
        return _snapshot(cached)

    product = _db.get(product_id)
    if product is None:
        return None

    # Populate cache and return a copy
    _cache[product_id] = _snapshot(product)
    return _snapshot(product)


def update_product(product_id: str, **fields) -> bool:
    """Update product fields in the database.

    Ensures the cache is updated so subsequent get_product calls return
    current data. Returns True if the product existed and was updated,
    otherwise False.
    """
    if product_id not in _db:
        return False

    _db[product_id].update(fields)
    # Refresh cache to avoid returning stale data
    _cache[product_id] = _snapshot(_db[product_id])
    return True


def reset() -> None:
    """Clear all data from the database and cache."""
    _db.clear()
    _cache.clear()
